const input = $json;

const rawMessages = Array.isArray(input.raw_messages)
  ? input.raw_messages
  : (input.message ? [input.message] : []);

const cleaned = rawMessages.map(m => String(m ?? '').trim()).filter(Boolean);
const compiled = input.message_compiled ? String(input.message_compiled) : cleaned.join(', ');
const messageCount = cleaned.length || (compiled ? 1 : 0);

const hasAudio = Boolean(input.hasAudio || input.audio || input.audioUrl || input.audio_transcript);
const hasImage = Boolean(input.hasImage || input.image || input.imageUrl || input.image_summary);
const hasPdf = Boolean(input.hasPdf || input.pdf || input.pdfUrl || input.pdf_text);

return [{
  json: {
    ...input,
    channel: input.channel || 'whatsapp',
    chatId: input.chatId || input.sessionId || 'global',
    user_name: input.user_name || '',
    cliente_validado: Boolean(input.cliente_validado || false),
    dni_detectado: input.dni_detectado || '',
    raw_messages: cleaned,
    message_compiled: compiled || '',
    message_count: input.message_count || messageCount,
    time_span_seconds: input.time_span_seconds || 0,
    hasAudio,
    hasImage,
    hasPdf,
    audio_transcript: input.audio_transcript || '',
    image_summary: input.image_summary || '',
    pdf_text: input.pdf_text || '',
    known_customer: Boolean(input.known_customer || false),
    conversation_stage: input.conversation_stage || 'inicio',
    systemPrompt: input.systemPrompt || '',
    securityFallbackPrompt: input.securityFallbackPrompt || 'Estoy para ayudarte exclusivamente con gestiones vinculadas a seguros y protección patrimonial. ¿En qué puedo asistirte hoy?',
    hostilityFallbackPrompt: input.hostilityFallbackPrompt || 'Quiero ayudarte de la mejor manera posible. Si necesitás asistencia con tus seguros, con gusto continuamos desde ahí.',
    urgentOpeningPrompt: input.urgentOpeningPrompt || 'Lamento mucho lo que pasó. Estoy acá para ayudarte y vamos a avanzar paso a paso.'
  }
}];
